import{_ as a,o as n,c as e,ak as r}from"./chunks/framework.DwHlt8HN.js";const k=JSON.parse('{"title":"Docker","description":"","frontmatter":{},"headers":[],"relativePath":"devops/docker/index.md","filePath":"devops/docker/index.md","lastUpdated":1774320699000}'),p={name:"devops/docker/index.md"};function l(o,s,t,i,c,d){return n(),e("div",null,[...s[0]||(s[0]=[r(`<h1 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to “Docker”">​</a></h1><p>容器化技术的代名词，也是现代 DevOps 的起点。</p><p>很多人第一次接触 Docker，是被「 build once, run anywhere 」打动的。但真正用进去之后，你会发现它解决的远不止「环境一致性问题」这么简单——它改变了整个软件的交付方式：从写代码到打包、从部署到扩缩容，所有环节都被重新定义。</p><p>这篇文章系列，会从 Docker 的基础概念讲起，覆盖镜像构建、数据持久化、网络通信，再到 Docker Swarm 集群编排，以及生产环境中绕不开的镜像优化、安全加固和日志管理。无论你是刚接触容器，还是想系统性地补齐 Docker 知识体系，都能找到对应的内容。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>Docker 不只是一个工具，它是一套生态。从镜像构建到多容器编排，每一块都有大量细节值得深究。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/docker/vm-vs-docker">Docker 基础</a></td><td>10 篇</td><td>核心概念、镜像构建、网络存储、Compose/Registry</td></tr><tr><td><a href="/devops/docker/container-communication">Docker 进阶</a></td><td>8 篇</td><td>通信原理、存储驱动、资源限制、安全配置</td></tr><tr><td><a href="/devops/docker/swarm-architecture">Docker Swarm</a></td><td>3 篇</td><td>集群架构、服务部署、负载均衡与服务发现</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：入门上手（1-2 天）</span></span>
<span class="line"><span>→ 安装 Docker，理解镜像、容器、仓库三大概念</span></span>
<span class="line"><span>→ 跑通 Dockerfile，构建第一个自定义镜像</span></span>
<span class="line"><span>→ 用 Docker Compose 起一个多容器应用（如 WordPress）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：生产级掌握（1 周）</span></span>
<span class="line"><span>→ 理解镜像分层与 Copy-on-Write 机制</span></span>
<span class="line"><span>→ 掌握数据持久化（Volume、Bind Mount）</span></span>
<span class="line"><span>→ 深入网络模式，理解容器间通信原理</span></span>
<span class="line"><span>→ 实践镜像优化：多阶段构建、.dockerignore、层缓存</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：集群与进阶（1 周）</span></span>
<span class="line"><span>→ Docker Swarm 集群部署与服务编排</span></span>
<span class="line"><span>→ 私有仓库搭建（Registry / Harbor）</span></span>
<span class="line"><span>→ 安全配置：用户命名空间、seccomp、capability</span></span>
<span class="line"><span>→ 日志驱动与资源限制</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h2 id="为什么-docker-是-devops-的入口" tabindex="-1">为什么 Docker 是 DevOps 的入口？ <a class="header-anchor" href="#为什么-docker-是-devops-的入口" aria-label="Permalink to “为什么 Docker 是 DevOps 的入口？”">​</a></h2><p>如果你在团队里推广过 CI/CD，大概率会遇到这个问题：「本地跑得好好的，怎么上线就挂了？」</p><p>根本原因往往是：<strong>开发环境、测试环境、生产环境的差异</strong>。操作系统版本不同、依赖库版本不同、甚至时区、语言环境都可能造成差异。</p><p>Docker 的核心价值，就是把这三个环境「合三为一」。你的应用连同它的所有依赖，打包成一个镜像，在任何装了 Docker 的机器上，跑出来的行为完全一致。</p><p>这也是 Kubernetes 出现之前，Docker 就已经火遍全球的原因——它解决了团队协作中最让人头疼的环境问题。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>Docker 面试的核心，不在于你会不会用 <code>docker run</code>，而在于你能不能讲清楚：</p><ol><li><strong>镜像层面</strong>：镜像分层的原理是什么？Copy-on-Write 带来了什么优势？多阶段构建解决了什么问题？</li><li><strong>网络层面</strong>：容器之间是怎么通信的？veth-pair 和 docker0 的作用是什么？自定义网络和默认 bridge 有什么区别？</li><li><strong>存储层面</strong>：Volume 和 Bind Mount 的区别是什么？什么场景用 tmpfs？</li><li><strong>安全层面</strong>：Docker 的隔离机制是怎么实现的？用户命名空间、capability、seccomp 各自解决了什么问题？</li><li><strong>编排层面</strong>：Docker Swarm 和 Kubernetes 的定位有什么不同？</li></ol><blockquote><p>&quot;会 <code>docker build</code> 的人很多，能讲清楚镜像分层原理的人很少。面试比的不是命令熟练度，而是对原理的理解深度。&quot;</p></blockquote>`,18)])])}const h=a(p,[["render",l]]);export{k as __pageData,h as default};
